#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long n; if(scanf("%lld", &n)!=1) return 0;
        int sum=0; while(n>0){ sum+= n%10; n/=10; }
        printf("%d\n", sum);
    }
    return 0;
}

